.validateModType <- function(mod_type, object) {
  valid <- levels(mcols(rowRanges(object))$mod_type)
  if (is.null(mod_type)) {
    return(valid)
  }
  if (length(mod_type) != 1) {
    stop("'mod_type' must be a single string or NULL")
  }
  if (!mod_type %in% valid) {
    stop(sprintf(
      "'mod_type' must be one of: %s",
      paste(valid, collapse = ", ")
    ))
  }
  mod_type
}
