diffMethyl <- function(object, design, method = "beta-binomial",
                      mod_type = NULL, min_coverage = 10) {
  object <- .validateModType(mod_type, object)
  if (min_coverage < 1) {
    stop("'min_coverage' must be >= 1")
  }
  gr <- rowRanges(object)
  mc <- mcols(gr)
  assays <- assay(object)
  meth <- assay(object, "methylation")
  cov <- assay(object, "coverage")
  low_cov <- rowSums(cov >= min_coverage) == ncol(object)
  if (method == "beta-binomial") {
    res <- .diffMethylBetaBinomial(meth, cov, design, mc)
  } else if (method == "limma") {
    res <- .diffMethylLimma(meth, cov, design, mc)
  } else if (method == "quasi_f") {
    res <- .diffMethylQuasiF(meth, cov, design, mc)
  }
  mcols(gr) <- cbind(mc, res)
  BiocGenerics:::`replaceRows<-`(object, gr)
}
